  "inlineSchema": "// ============================================================\n// PRISMA SCHEMA - Metal Trading Platform\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── ENUMS ──────────────────────────────────────────────────\n\nenum UserStatus {\n  ACTIVE\n  SUSPENDED\n  PENDING_VERIFICATION\n}\n\nenum TransactionType {\n  BUY\n  SELL\n  DEPOSIT\n  WITHDRAWAL\n}\n\nenum OrderStatus {\n  PENDING\n  EXECUTED\n  CANCELLED\n  FAILED\n}\n\nenum OrderType {\n  BUY\n  SELL\n}\n\nenum WithdrawalStatus {\n  PENDING\n  READY_FOR_PICKUP\n  COMPLETED\n  EXPIRED\n  CANCELLED\n}\n\n// ─── MODELS ─────────────────────────────────────────────────\n\nmodel User {\n  id           String     @id @default(uuid())\n  email        String     @unique\n  passwordHash String     @map(\"password_hash\")\n  status       UserStatus @default(ACTIVE)\n  createdAt    DateTime   @default(now()) @map(\"created_at\")\n  updatedAt    DateTime   @updatedAt @map(\"updated_at\")\n\n  wallets      Wallet[]\n  transactions Transaction[]\n  orders       Order[]\n  withdrawals  Withdrawal[]\n\n  @@index([email])\n  @@map(\"users\")\n}\n\nmodel Metal {\n  id        String   @id @default(uuid())\n  name      String   @unique // \"Copper\", \"Aluminium\"\n  symbol    String   @unique // \"CU\", \"AL\"\n  unit      String   @default(\"kg\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  wallets      Wallet[]\n  transactions Transaction[]\n  orders       Order[]\n  inventory    Inventory?\n  withdrawals  Withdrawal[]\n  prices       Price[]\n\n  @@map(\"metals\")\n}\n\nmodel Wallet {\n  id        String   @id @default(uuid())\n  userId    String   @map(\"user_id\")\n  metalId   String?  @map(\"metal_id\") // NULL = USD wallet\n  balance   Decimal  @default(0) @db.Decimal(18, 8)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  user  User   @relation(fields: [userId], references: [id])\n  metal Metal? @relation(fields: [metalId], references: [id])\n\n  @@unique([userId, metalId])\n  @@index([userId])\n  @@map(\"wallets\")\n}\n\n/// LEDGER — append-only, no updates or deletes ever\nmodel Transaction {\n  id          String          @id @default(uuid())\n  userId      String          @map(\"user_id\")\n  type        TransactionType\n  metalId     String?         @map(\"metal_id\")\n  amount      Decimal         @db.Decimal(18, 8) // kg or USD depending on type\n  price       Decimal?        @db.Decimal(18, 8) // USD per kg\n  totalUsd    Decimal?        @map(\"total_usd\") @db.Decimal(18, 8)\n  referenceId String?         @map(\"reference_id\") // orderId or withdrawalId\n  metadata    Json? // extra context (spread, fees, etc.)\n  createdAt   DateTime        @default(now()) @map(\"created_at\")\n\n  user  User   @relation(fields: [userId], references: [id])\n  metal Metal? @relation(fields: [metalId], references: [id])\n\n  @@index([userId])\n  @@index([referenceId])\n  @@index([createdAt])\n  @@map(\"transactions\")\n}\n\nmodel Order {\n  id         String      @id @default(uuid())\n  userId     String      @map(\"user_id\")\n  type       OrderType\n  metalId    String      @map(\"metal_id\")\n  amountKg   Decimal     @map(\"amount_kg\") @db.Decimal(18, 8)\n  price      Decimal     @db.Decimal(18, 8) // execution price USD/kg\n  totalUsd   Decimal     @map(\"total_usd\") @db.Decimal(18, 8)\n  status     OrderStatus @default(PENDING)\n  createdAt  DateTime    @default(now()) @map(\"created_at\")\n  executedAt DateTime?   @map(\"executed_at\")\n\n  user  User  @relation(fields: [userId], references: [id])\n  metal Metal @relation(fields: [metalId], references: [id])\n\n  @@index([userId])\n  @@index([metalId])\n  @@index([status])\n  @@map(\"orders\")\n}\n\nmodel Inventory {\n  id             String   @id @default(uuid())\n  metalId        String   @unique @map(\"metal_id\")\n  totalStock     Decimal  @map(\"total_stock\") @db.Decimal(18, 8)\n  reservedStock  Decimal  @default(0) @map(\"reserved_stock\") @db.Decimal(18, 8)\n  availableStock Decimal  @map(\"available_stock\") @db.Decimal(18, 8)\n  updatedAt      DateTime @updatedAt @map(\"updated_at\")\n\n  metal Metal @relation(fields: [metalId], references: [id])\n\n  @@map(\"inventory\")\n}\n\nmodel Price {\n  id        String    @id @default(uuid())\n  metalId   String    @map(\"metal_id\")\n  buyPrice  Decimal   @map(\"buy_price\") @db.Decimal(18, 8) // platform sells at this\n  sellPrice Decimal   @map(\"sell_price\") @db.Decimal(18, 8) // platform buys at this\n  spread    Decimal   @db.Decimal(5, 4)\n  validFrom DateTime  @default(now()) @map(\"valid_from\")\n  validTo   DateTime? @map(\"valid_to\")\n  createdAt DateTime  @default(now()) @map(\"created_at\")\n\n  metal Metal @relation(fields: [metalId], references: [id])\n\n  @@index([metalId, validFrom])\n  @@map(\"prices\")\n}\n\nmodel Withdrawal {\n  id         String           @id @default(uuid())\n  userId     String           @map(\"user_id\")\n  metalId    String           @map(\"metal_id\")\n  amountKg   Decimal          @map(\"amount_kg\") @db.Decimal(18, 8)\n  status     WithdrawalStatus @default(PENDING)\n  pickupCode String?          @unique @map(\"pickup_code\")\n  expiresAt  DateTime?        @map(\"expires_at\")\n  createdAt  DateTime         @default(now()) @map(\"created_at\")\n  updatedAt  DateTime         @updatedAt @map(\"updated_at\")\n\n  user  User  @relation(fields: [userId], references: [id])\n  metal Metal @relation(fields: [metalId], references: [id])\n\n  @@index([userId])\n  @@index([pickupCode])\n  @@map(\"withdrawals\")\n}\n",
